#include <iostream>
#include <cmath>

int main() {
    double a, b;
    std::cin >> a >> b;

    if (std::abs(a - b) < 1e-9) {
        std::cout << "equal\n";
    } else {
        std::cout << "not equal\n";
    }
    return 0;
}
